import React from 'react';

import type { StoreLang, StoreProps, StoreType } from './Store.types';

import './Store.scss';

import { classNames } from ':helpers/classnames';

import AppGalleryBlackEn from './icons/AppGalleryBlackEn';
import AppGalleryBlackRu from './icons/AppGalleryBlackRu';
import AppGalleryWhiteEn from './icons/AppGalleryWhiteEn';
import AppGalleryWhiteRu from './icons/AppGalleryWhiteRu';
import AppStoreBlackEn from './icons/AppStoreBlackEn';
import AppStoreBlackRu from './icons/AppStoreBlackRu';
import AppStoreWhiteEn from './icons/AppStoreWhiteEn';
import AppStoreWhiteRu from './icons/AppStoreWhiteRu';
import GooglePlayBlackEn from './icons/GooglePlayBlackEn';
import GooglePlayBlackRu from './icons/GooglePlayBlackRu';
import GooglePlayWhiteEn from './icons/GooglePlayWhiteEn';
import GooglePlayWhiteRu from './icons/GooglePlayWhiteRu';

const ariaLabels: Record<StoreType, Record<StoreLang, string>> = {
	appstore: {
		ru: 'Скачать в App Store',
		en: 'Download on the App Store',
	},
	googleplay: {
		ru: 'Скачать в Google Play',
		en: 'Get it on Google Play',
	},
	appgallery: {
		ru: 'Скачать в AppGallery',
		en: 'Get it on AppGallery',
	},
};

const iconsMap = {
	appstore: {
		black: {
			ru: AppStoreBlackRu,
			en: AppStoreBlackEn,
		},
		white: {
			ru: AppStoreWhiteRu,
			en: AppStoreWhiteEn,
		},
	},
	googleplay: {
		black: {
			ru: GooglePlayBlackRu,
			en: GooglePlayBlackEn,
		},
		white: {
			ru: GooglePlayWhiteRu,
			en: GooglePlayWhiteEn,
		},
	},
	appgallery: {
		black: {
			ru: AppGalleryBlackRu,
			en: AppGalleryBlackEn,
		},
		white: {
			ru: AppGalleryWhiteRu,
			en: AppGalleryWhiteEn,
		},
	},
} as const;

export const Store: React.FC<StoreProps> = ({
	store,
	theme,
	lang,
	href,
	className,
	dataTestId = 'Store',
	ariaLabel,
	...rest
}) => {
	const StoreIcon = iconsMap[store][theme][lang];
	const label = ariaLabel || ariaLabels[store][lang];

	return (
		<a
			{...rest}
			href={href}
			className={classNames('dsb_store', `dsb_store--${store}`, `dsb_store--${theme}`, `dsb_store--${lang}`, className)}
			data-testid={dataTestId}
			aria-label={label}
		>
			<StoreIcon aria-hidden="true" />
		</a>
	);
};
